<template><view class="page"><view class="header"><text class="title">我的行程</text><text class="new-link" @click="create">新建行程</text></view><view v-if="loading" class="empty">行程加载中</view><view v-else-if="!list.length" class="empty">还没有保存的行程</view><view v-else class="list"><view v-for="item in list" :key="item.id" class="item" @click="open(item.id)"><view><text class="name">{{ item.name }}</text><text class="date">{{ item.start_date }} 至 {{ item.end_date }} · {{ item.day_count }} 天</text><text class="summary">约 {{ distanceText(item.distance_meters) }} · 驾车 {{ item.duration_minutes || 0 }} 分钟</text></view><text class="arrow">›</text></view></view><AppBottomNav active="travel" /></view></template>
<script setup>import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppBottomNav from'../../components/AppBottomNav.vue';import{getTravelItineraries}from'../../api/travel';const list=ref([]),loading=ref(false);const distanceText=value=>Number(value)>=1000?`${(Number(value)/1000).toFixed(1)} km`:`${value||0} m`;const load=async()=>{loading.value=true;try{list.value=(await getTravelItineraries()).data?.list||[]}catch(error){uni.showToast({title:error.msg||'读取失败',icon:'none'})}finally{loading.value=false}};const open=id=>uni.navigateTo({url:`/pages/travel/itinerary?id=${id}`});const create=()=>uni.navigateTo({url:'/pages/travel/plan'});onShow(load)</script>
<style scoped>.page{min-height:100vh;padding:26rpx 24rpx calc(210rpx + env(safe-area-inset-bottom));box-sizing:border-box;background:#f5f7fa}.header{display:flex;justify-content:space-between;align-items:center}.title{font-size:36rpx;font-weight:700;color:#1f2937}.new-link{color:#1677ff;font-size:26rpx}.list{margin-top:22rpx;border-radius:8rpx;background:#fff;overflow:hidden}.item{display:flex;justify-content:space-between;align-items:center;padding:26rpx 22rpx;border-bottom:1rpx solid #edf0f5}.item:last-child{border:0}.name,.date,.summary{display:block}.name{font-size:29rpx;font-weight:600;color:#1f2937}.date{margin-top:10rpx;color:#66758a;font-size:23rpx}.summary{margin-top:8rpx;color:#0f8e69;font-size:22rpx}.arrow{color:#94a3b8;font-size:42rpx}.empty{padding:120rpx 0;color:#94a3b8;text-align:center;font-size:25rpx}</style>
